import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote: empty and basic single-item base premiums
  it.todo("empty item list yields premium of 5 G (processing fee only)");
  it.todo("quote for a single plain sword yields 105 G (100 + 5)");
  it.todo("quote for a single plain amulet yields 65 G (60 + 5)");
  it.todo("quote for a single plain staff yields 85 G (80 + 5)");
  it.todo("quote for a single plain potion yields 45 G (40 + 5)");

  // Components and the 3-alike block
  it.todo("quote for 2 runes yields 55 G (2*25 + 5)");
  it.todo("quote for 3 alike runes yields 65 G (block 60 + 5)");
  it.todo("quote for 4 runes yields 105 G (no block: 4*25 + 5)");
  it.todo("quote for 2 runes + 1 moonstone yields 80 G (no block, different types)");
  it.todo("quote for 3 runes + 3 moonstones yields 125 G (two separate blocks: 60+60+5)");

  // Item-specific premium modifiers
  it.todo("cursed sword adds 50% surcharge on that item only (newcomer first insurance: 165 G)");
  it.todo("high-enchantment sword (level 5) adds 30% surcharge");
  it.todo("sword with enchantment 4 has no high-enchantment surcharge");

  // Policy-wide modifiers
  it.todo("first-ever quote adds 10% first-insurance surcharge");
  it.todo("loyalty discount of 20% applies when customer has >= 2 years");
  it.todo("follow-up contract discount of 15% applies on second and later quotes");
  it.todo("rounding goes in MHPCO's favor (premium rounds up)");

  // Claim processing - basics
  it.todo("plain sword damage 500 G yields payout 400 G (full minus 100 deductible)");
  it.todo("plain sword damage 200 G yields payout 100 G after deductible");
  it.todo("high-enchantment (level 8) item reimbursed at 50% then deductible");
  it.todo("dragon-material item is fully reimbursed then deductible");
  it.todo("dragon material with high enchantment: 50% rule wins");
  it.todo("payout cap is twice insurance sum; exhausts across successive claims");
  it.todo("deductible applies once per damaged item in a multi-damage event");

  // CLI / validation errors
  it.todo("unknown item type in quote causes non-zero exit / error");
  it.todo("claim references item not in policy causes error");
  it.todo("negative damage amount causes error");
});

