export type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };

export type Step = { op: string; items?: Item[]; policy?: number; incident?: unknown };

export type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

export type ScenarioResult = {
  results: Array<{ premium?: number; payout?: number; remainingCap?: number }>;
};

const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step) => {
    const items = step.items ?? [];
    const base = items.reduce((sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0);
    return { premium: base + PROCESSING_FEE };
  });
  return { results };
};

