const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const groupComponentsByType = (items: Item[]): Map<string, Item[]> => {
  const groups = new Map<string, Item[]>();
  for (const item of items) {
    if (!COMPONENT_TYPES.has(item.type)) continue;
    const group = groups.get(item.type) ?? [];
    group.push(item);
    groups.set(item.type, group);
  }
  return groups;
};

const premiumForGroup = (group: Item[]): number =>
  group.length === BLOCK_SIZE
    ? BLOCK_PREMIUM
    : group.reduce((total, item) => total + basePremiumFor(item), 0);

const totalBasePremiumFor = (items: Item[]): number => {
  const componentGroups = groupComponentsByType(items);
  let total = 0;
  for (const group of componentGroups.values()) total += premiumForGroup(group);
  for (const item of items) {
    if (!COMPONENT_TYPES.has(item.type)) total += basePremiumFor(item);
  }
  return total;
};

