export type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };

export type Step = { op: string; items?: Item[]; policy?: number; incident?: unknown };

export type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

export type ScenarioResult = {
  results: StepResult[];
};

const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

type StepResult = { premium?: number; payout?: number; remainingCap?: number };

const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;

const isThreeAlikeRuneBlock = (items: Item[]): boolean =>
  items.length === BLOCK_SIZE && items.every((item) => item.type === "rune");

const totalBasePremiumFor = (items: Item[]): number => {
  if (isThreeAlikeRuneBlock(items)) return BLOCK_PREMIUM;
  return items.reduce((total, item) => total + basePremiumFor(item), 0);
};

const quotePremium = (items: Item[]): number => totalBasePremiumFor(items) + PROCESSING_FEE;

const processStep = ({ items = [] }: Step): StepResult => ({ premium: quotePremium(items) });

export const runScenario = (scenario: Scenario): ScenarioResult => ({
  results: scenario.steps.map(processStep),
});

