  return Math.ceil(base + curseSurcharge + firstInsuranceSurcharge + PROCESSING_FEE);
};

const processStep = ({ items = [] }: Step): StepResult => ({ premium: quotePremium(items) });

export const runScenario = (scenario: Scenario): ScenarioResult => ({
  results: scenario.steps.map(processStep),
});

