const isHighlyEnchanted = (item: Item): boolean =>
  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;

const curseSurchargeFor = (items: Item[]): number =>
  itemSurchargeFor(items, isCursed, CURSE_SURCHARGE_RATE);

const highEnchantmentSurchargeFor = (items: Item[]): number =>
  itemSurchargeFor(items, isHighlyEnchanted, HIGH_ENCHANTMENT_RATE);

const firstInsuranceSurchargeFor = (base: number): number => base * FIRST_INSURANCE_RATE;

const quotePremium = (items: Item[]): number => {
  const base = totalBasePremiumFor(items);
  const curseSurcharge = curseSurchargeFor(items);
  const highEnchantmentSurcharge = highEnchantmentSurchargeFor(items);
  const firstInsuranceSurcharge = firstInsuranceSurchargeFor(base);
  return Math.ceil(
    base + curseSurcharge + highEnchantmentSurcharge + firstInsuranceSurcharge + PROCESSING_FEE,
  );
};

const processStep = ({ items = [] }: Step): StepResult => ({ premium: quotePremium(items) });

export const runScenario = (scenario: Scenario): ScenarioResult => ({
  results: scenario.steps.map(processStep),
});

