const HIGH_ENCHANTMENT_THRESHOLD = 5;
const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_YEARS_THRESHOLD = 2;

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;

const groupKeyFor = (item: Item, index: number): string =>
  COMPONENT_TYPES.has(item.type) ? item.type : `item:${index}`;

const groupItemsForPricing = (items: Item[]): Item[][] => {
  const groups = new Map<string, Item[]>();
  items.forEach((item, index) => {
    const key = groupKeyFor(item, index);
    const group = groups.get(key) ?? [];
    group.push(item);
    groups.set(key, group);
  });
  return [...groups.values()];
};

const premiumForGroup = (group: Item[]): number =>
  group.length === BLOCK_SIZE
    ? BLOCK_PREMIUM
    : group.reduce((total, item) => total + basePremiumFor(item), 0);

const totalBasePremiumFor = (items: Item[]): number =>
  groupItemsForPricing(items).reduce((total, group) => total + premiumForGroup(group), 0);

const itemSurchargeFor = (
  items: Item[],
  qualifies: (item: Item) => boolean,
  rate: number,
): number =>
  items.reduce(
    (total, item) => (qualifies(item) ? total + basePremiumFor(item) * rate : total),
    0,
  );

const isCursed = (item: Item): boolean => item.cursed === true;

const isHighlyEnchanted = (item: Item): boolean =>
  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;

type PolicyModifier = (base: number, items: Item[], customer: Customer) => number;

const POLICY_MODIFIERS: PolicyModifier[] = [
  (_base, items) => itemSurchargeFor(items, isCursed, CURSE_SURCHARGE_RATE),
  (_base, items) => itemSurchargeFor(items, isHighlyEnchanted, HIGH_ENCHANTMENT_RATE),
  (base) => base * FIRST_INSURANCE_RATE,
  (base, _items, customer) =>
    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? -(base * LOYALTY_DISCOUNT_RATE) : 0,
];

const sumModifiers = (base: number, items: Item[], customer: Customer): number =>
  POLICY_MODIFIERS.reduce((total, modifier) => total + modifier(base, items, customer), 0);

const quotePremium = (items: Item[], customer: Customer): number => {
  const base = totalBasePremiumFor(items);
  return Math.ceil(base + sumModifiers(base, items, customer) + PROCESSING_FEE);
};

const processStep = ({ items = [] }: Step, customer: Customer): StepResult => ({
  premium: quotePremium(items, customer),
});

export const runScenario = (scenario: Scenario): ScenarioResult => ({
  results: scenario.steps.map((step) => processStep(step, scenario.customer)),
});

