import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote: empty and basic single-item base premiums
  it("empty item list yields premium of 5 G (processing fee only)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });
  it("quote for a single plain sword yields 115 G (100 + 10 first-ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("quote for a single plain amulet yields 71 G (60 + 6 first-ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("quote for a single plain staff yields 93 G (80 + 8 first-ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "staff", material: "wood", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("quote for a single plain potion yields 49 G (40 + 4 first-ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });

  // Components and the 3-alike block
  it("quote for 2 runes yields 60 G (50 + 5 first-ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("quote for 3 alike runes yields 71 G (block 60 + 6 first-ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("quote for 4 runes yields 115 G (4*25 + 10 first-ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("quote for 2 runes + 1 moonstone yields 88 G (75 + 7.5 first-ins + 5 fee = 87.5, rounded up)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 88 }] });
  });
  it("quote for 3 runes + 3 moonstones yields 137 G (120 + 12 first-ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
            { type: "moonstone" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });

  // Item-specific premium modifiers
  it("cursed sword adds 50% surcharge on that item only (newcomer first insurance: 165 G)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it("high-enchantment sword (level 5) adds 30% surcharge → 145 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 145 }] });
  });
  it("sword with enchantment 4 has no high-enchantment surcharge → 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 4, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });

  // Policy-wide modifiers (first-insurance is exercised by all prior single-item tests)
  it("loyalty discount of 20% applies when customer has >= 2 years → sword 95 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 95 }] });
  });
  it("follow-up contract discount of 15% applies on second and later quotes", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }, { premium: 100 }] });
  });
  it.todo("rounding goes in MHPCO's favor (premium rounds up)");

  // Claim processing - basics
  it.todo("plain sword damage 500 G yields payout 400 G (full minus 100 deductible)");
  it.todo("plain sword damage 200 G yields payout 100 G after deductible");
  it.todo("high-enchantment (level 8) item reimbursed at 50% then deductible");
  it.todo("dragon-material item is fully reimbursed then deductible");
  it.todo("dragon material with high enchantment: 50% rule wins");
  it.todo("payout cap is twice insurance sum; exhausts across successive claims");
  it.todo("deductible applies once per damaged item in a multi-damage event");

  // CLI / validation errors
  it.todo("unknown item type in quote causes non-zero exit / error");
  it.todo("claim references item not in policy causes error");
  it.todo("negative damage amount causes error");
});

export type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };

export type Customer = { yearsWithMHPCO: number };

export type Step = { op: string; items?: Item[]; policy?: number; incident?: unknown };

export type Scenario = {
  customer: Customer;
  steps: Step[];
};

export type ScenarioResult = {
  results: StepResult[];
};

const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

type StepResult = { premium?: number; payout?: number; remainingCap?: number };

const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const CURSE_SURCHARGE_RATE = 0.5;
const FIRST_INSURANCE_RATE = 0.1;
const HIGH_ENCHANTMENT_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_YEARS_THRESHOLD = 2;

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;

const groupKeyFor = (item: Item, index: number): string =>
  COMPONENT_TYPES.has(item.type) ? item.type : `item:${index}`;

const groupItemsForPricing = (items: Item[]): Item[][] => {
  const groups = new Map<string, Item[]>();
  items.forEach((item, index) => {
    const key = groupKeyFor(item, index);
    const group = groups.get(key) ?? [];
    group.push(item);
    groups.set(key, group);
  });
  return [...groups.values()];
};

const premiumForGroup = (group: Item[]): number =>
  group.length === BLOCK_SIZE
    ? BLOCK_PREMIUM
    : group.reduce((total, item) => total + basePremiumFor(item), 0);

const totalBasePremiumFor = (items: Item[]): number =>
  groupItemsForPricing(items).reduce((total, group) => total + premiumForGroup(group), 0);

const itemSurchargeFor = (
  items: Item[],
  qualifies: (item: Item) => boolean,
  rate: number,
): number =>
  items.reduce(
    (total, item) => (qualifies(item) ? total + basePremiumFor(item) * rate : total),
    0,
  );

const isCursed = (item: Item): boolean => item.cursed === true;

const isHighlyEnchanted = (item: Item): boolean =>
  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;

type PolicyModifier = (base: number, items: Item[], customer: Customer) => number;

const POLICY_MODIFIERS: PolicyModifier[] = [
  (_base, items) => itemSurchargeFor(items, isCursed, CURSE_SURCHARGE_RATE),
  (_base, items) => itemSurchargeFor(items, isHighlyEnchanted, HIGH_ENCHANTMENT_RATE),
  (base) => base * FIRST_INSURANCE_RATE,
  (base, _items, customer) =>
    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? -(base * LOYALTY_DISCOUNT_RATE) : 0,
];

const sumModifiers = (base: number, items: Item[], customer: Customer): number =>
  POLICY_MODIFIERS.reduce((total, modifier) => total + modifier(base, items, customer), 0);

const quotePremium = (items: Item[], customer: Customer): number => {
  const base = totalBasePremiumFor(items);
  return Math.ceil(base + sumModifiers(base, items, customer) + PROCESSING_FEE);
};

const processStep = ({ items = [] }: Step, customer: Customer): StepResult => ({
  premium: quotePremium(items, customer),
});

export const runScenario = (scenario: Scenario): ScenarioResult => ({
  results: scenario.steps.map((step) => processStep(step, scenario.customer)),
});

