const processClaim = (
  step: Step,
  scenario: Scenario,
  alreadyPaid: number,
): { result: StepResult; paid: number } => {
  const policyItems = policyItemsFor(step, scenario);
  const cap = CAP_MULTIPLIER * insuranceSumOf(policyItems);
  const desired = totalPayoutFor(damagesIn(step), policyItems);
  const payout = Math.min(desired, cap - alreadyPaid);
  return { result: { payout, remainingCap: cap - alreadyPaid - payout }, paid: alreadyPaid + payout };
};

type RunState = { results: StepResult[]; paidByPolicy: Map<number, number> };

const processStep = (
  state: RunState,
  step: Step,
  scenario: Scenario,
  quoteIndex: number,
): RunState => {
  if (step.op === "claim") {
    const policyIndex = step.policy ?? 0;
    const alreadyPaid = state.paidByPolicy.get(policyIndex) ?? 0;
    const { result, paid } = processClaim(step, scenario, alreadyPaid);
    const paidByPolicy = new Map(state.paidByPolicy);
    paidByPolicy.set(policyIndex, paid);
    return { results: [...state.results, result], paidByPolicy };
  }
  const result: StepResult = {
    premium: quotePremium(step.items ?? [], { customer: scenario.customer, quoteIndex }),
  };
  return { results: [...state.results, result], paidByPolicy: state.paidByPolicy };
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const initial: RunState = { results: [], paidByPolicy: new Map() };
  const final = scenario.steps.reduce(
    (state, step, index) => processStep(state, step, scenario, index),
    initial,
  );
  return { results: final.results };
};

